+
+test('Codex cleanup ignores contaminated backups and strips managed config lines', () => {
+  const { root: pkgRoot } = createPackageFixture();
+  const home = createHomeFixture();
+
+  writeText(
+    join(home, '.codex', 'config.toml'),
+    [
